/**
 * Redis-backed cache provider for @mui/x-studio-data-middleware.
 *
 * Implements `CacheProvider` using any Redis-compatible client.
 * Use this in multi-node or serverless deployments where `LRUCacheProvider`
 * (in-process only) would give each node an isolated cache.
 *
 * ## Supported clients
 *
 * This class accepts any object that conforms to the minimal `RedisClient`
 * interface below — it is compatible with both `ioredis` and `node-redis` (v4+)
 * without requiring either as a peer dependency.
 *
 * ### ioredis
 * ```ts
 * import Redis from 'ioredis';
 * import { RedisCacheProvider } from '@mui/x-studio-data-middleware';
 *
 * const redis = new Redis({ host: 'localhost', port: 6379 });
 * const cache = new RedisCacheProvider(redis);
 * ```
 *
 * ### node-redis (v4+)
 * ```ts
 * import { createClient } from 'redis';
 * import { RedisCacheProvider } from '@mui/x-studio-data-middleware';
 *
 * const redis = await createClient({ url: 'redis://localhost:6379' }).connect();
 * const cache = new RedisCacheProvider(redis);
 * ```
 *
 * ## TTL
 *
 * The default TTL is 60 seconds. Override per-call via `set(key, value, ttlSeconds)`
 * or set a default in the constructor options.
 *
 * ## Key format
 *
 * Cache keys are HMAC-scoped (generated by `generateCacheKey`) — they already
 * encode tenant and user context, so no additional namespacing is required
 * unless you share one Redis instance across multiple Studio deployments.
 * Use `keyPrefix` in the constructor options for that case.
 */

import type { CacheProvider, CacheEntry } from './types';

export interface RedisClient {
  get(key: string): Promise<string | null>;
  set(key: string, value: string, exMode: 'EX', ttlSeconds: number): Promise<unknown>;
  keys(pattern: string): Promise<string[]>;
  del(...keys: string[]): Promise<unknown>;
}

export interface RedisCacheProviderOptions {
  /**
   * Default TTL in seconds for `set()` calls that don't specify one.
   * @default 60
   */
  defaultTtlSeconds?: number;
  /**
   * Optional key prefix applied to every Redis key.
   * Useful when sharing one Redis instance across multiple deployments.
   * @example 'studio:prod:'
   */
  keyPrefix?: string;
}

export class RedisCacheProvider implements CacheProvider {
  private readonly redis: RedisClient;
  private readonly defaultTtl: number;
  private readonly prefix: string;

  constructor(redis: RedisClient, options: RedisCacheProviderOptions = {}) {
    this.redis = redis;
    this.defaultTtl = options.defaultTtlSeconds ?? 60;
    this.prefix = options.keyPrefix ?? '';
  }

  async get(key: string): Promise<CacheEntry | undefined> {
    const raw = await this.redis.get(this.prefix + key);
    if (!raw) {
      return undefined;
    }
    try {
      return JSON.parse(raw) as CacheEntry;
    } catch {
      return undefined;
    }
  }

  async set(key: string, value: CacheEntry, ttlSeconds?: number): Promise<void> {
    const ttl = ttlSeconds ?? this.defaultTtl;
    await this.redis.set(this.prefix + key, JSON.stringify(value), 'EX', ttl);
  }

  async invalidatePrefix(prefix: string): Promise<void> {
    const pattern = `${this.prefix}${prefix}*`;
    const keys = await this.redis.keys(pattern);
    if (keys.length > 0) {
      await this.redis.del(...keys);
    }
  }
}
